'use client';

import { useState, useEffect } from 'react';
import { motion, useMotionValue, useTransform, AnimatePresence } from 'framer-motion';
import {
  Users, User, Star, Layers, CheckSquare, Send,
  Sun, Moon, LogOut, Search, Flame, Sparkles,
  Check, CheckCircle, XCircle, RefreshCw, MapPin,
  AlertCircle, X, Heart,
} from 'lucide-react';
import { dbService, USE_MOCK } from '@/lib/firebase';
